import{_ as a,o as i,c as t,a3 as s}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Templating","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/templating.md","filePath":"cosmos/framework/packages/templating.md","lastUpdated":1783216089000}'),n={name:"cosmos/framework/packages/templating.md"};function l(r,e,o,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="xihan-framework-templating" tabindex="-1">XiHan.Framework.Templating <a class="header-anchor" href="#xihan-framework-templating" aria-label="Permalink to &quot;XiHan.Framework.Templating&quot;">​</a></h1><blockquote><p>模板渲染：内置 Scriban 引擎与轻量字符串替换引擎，通过引擎注册表按名称统一管理。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Templating</code></li><li><strong>模块类</strong>：<code>XiHanTemplatingModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Templating 提供模板渲染能力，并把多种模板引擎统一到一个注册表 <code>ITemplateEngineRegistry</code> 下按名称管理。框架内置两种引擎：功能完整的 <strong>Scriban</strong> 引擎（注册名 <code>&quot;Scriban&quot;</code>）和一个轻量的<strong>字符串替换</strong>引擎（注册名 <code>&quot;String&quot;</code>）。适合代码生成、通知/邮件文案、报表等需要「模板 + 数据 = 文本」的场景。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要把数据填进模板生成文本（代码文件、邮件正文、通知内容等）。</li><li>需要在同一套 API 下切换/共存多种模板引擎。</li><li>需要模板缓存、语法校验、从文件渲染等配套能力。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Templating</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanTemplatingModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>OnApplicationInitialization</code> 时把 Scriban 引擎与 String 引擎注册进 <code>ITemplateEngineRegistry</code>，并分别设为对应模板类型的默认引擎。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>引擎注册表</strong>：<code>ITemplateEngineRegistry</code> 按名称注册、获取引擎，并可设置某模板类型的默认引擎。</li><li><strong>两种内置引擎</strong>：Scriban 引擎（<code>ITemplateEngine&lt;Template&gt;</code>，注册名 <code>&quot;Scriban&quot;</code>）与字符串替换引擎（<code>ITemplateEngine&lt;string&gt;</code>，注册名 <code>&quot;String&quot;</code>）。</li><li><strong>模板服务</strong>：<code>ITemplateService</code> 提供 <code>RenderAsync</code> / <code>RenderFileAsync</code> / <code>ValidateTemplate</code> 等入口，屏蔽底层引擎细节。</li><li><strong>配套能力</strong>：模板缓存、语法校验（<code>TemplateValidationResult</code>）、从文件渲染、渲染结果落盘等。</li><li><strong>可配置</strong>：<code>TemplatingOptions</code> 支持默认引擎、缓存开关与过期、渲染超时、模板大小上限、模板/布局/片段目录等。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>ITemplateEngineRegistry</code> / <code>TemplateEngineRegistry</code></td><td>模板引擎注册表</td></tr><tr><td><code>ITemplateEngine&lt;T&gt;</code></td><td>模板引擎接口（<code>Parse</code> / <code>Render</code> / <code>RenderAsync</code> / <code>Validate</code>）</td></tr><tr><td><code>ScribanTemplateEngine</code></td><td>基于 Scriban 的引擎实现（<code>ITemplateEngine&lt;Template&gt;</code>）</td></tr><tr><td><code>DefaultTemplateEngine</code></td><td>轻量字符串替换引擎（<code>ITemplateEngine&lt;string&gt;</code>）</td></tr><tr><td><code>ITemplateService</code> / <code>TemplateService</code></td><td>面向业务的模板服务门面</td></tr><tr><td><code>TemplatingOptions</code></td><td>模板行为配置</td></tr></tbody></table><h2 id="重要澄清-itemplateservice-默认走的不是-scriban" tabindex="-1">重要澄清：ITemplateService 默认走的不是 Scriban <a class="header-anchor" href="#重要澄清-itemplateservice-默认走的不是-scriban" aria-label="Permalink to &quot;重要澄清：ITemplateService 默认走的不是 Scriban&quot;">​</a></h2><p><code>ITemplateService.RenderAsync(templateSource, ...)</code> 内部取的是 <strong><code>string</code> 模板类型的默认引擎</strong>，即注册名 <code>&quot;String&quot;</code> 的 <code>DefaultTemplateEngine</code>。它是一个<strong>简单替换引擎</strong>：只支持形如 <code>{{变量}}</code> 的占位替换，以及自定义的 <code>{{if ...}}...{{endif}}</code>、<code>{{for x in list}}...{{endfor}}</code> 语法，<strong>并不解析 Scriban 语法</strong>（Scriban 的过滤器、函数、复杂表达式等在这里无效）。</p><p>因此，如果你要用真正的 Scriban 模板（<code>{{ name | string.upcase }}</code> 之类），不要依赖 <code>ITemplateService</code> 的字符串重载，应改用 Scriban 引擎路径：</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 真正跑 Scriban：用原生 Scriban API</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> template</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Scriban.Template.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Parse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello {{ name | string.upcase }}!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> result</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> template.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Render</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;xihan&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span></code></pre></div><p>也可从注册表按名取出 Scriban 引擎：<code>registry.GetEngine&lt;Template&gt;(&quot;Scriban&quot;)</code>。切勿误以为把 Scriban 语法丢给 <code>ITemplateService</code> 就会被 Scriban 解析。</p><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./core">XiHan.Framework.Core</a> — 模块化与依赖注入基础。</li><li><a href="./serialization">XiHan.Framework.Serialization</a> — 序列化支持（模块通过 <code>[DependsOn]</code> 依赖）。</li><li><a href="./utils">XiHan.Framework.Utils</a> — 通用工具库。</li></ul><p>第三方核心依赖：<code>Scriban</code>（模板引擎）。</p><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./virtual-file-system">XiHan.Framework.VirtualFileSystem</a> — 需要从虚拟路径加载模板资源时可配合使用。</li></ul>`,26)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
